/* ── Formatters ─────────────────────────────────────────── */

const fVnd = (v: number): string =>
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(v);

const fCompact = (v: number): string => {
  const abs = Math.abs(v);
  if (abs >= 1_000_000_000) return `${(abs / 1_000_000_000).toFixed(1)} tỷ`;
  if (abs >= 1_000_000) return `${(abs / 1_000_000).toFixed(0)} tr`;
  if (abs >= 1_000) return `${(abs / 1_000).toFixed(0)} ng`;
  return `${abs.toLocaleString('vi-VN')}`;
};

const pct = (v: number): string => `${v >= 0 ? '+' : ''}${v.toFixed(1)}%`;

const chartCurrency = (v: number): string => `${(v / 1_000_000).toFixed(0)}tr`;

interface AlertColors { [key: string]: string; }

