const MOCK_DAILY_DAYS = Array.from({ length: 14 }, (_, i) => {
  const d = new Date(2026, 6, 21 + i);
  const opening = 11_200_000_000 + i * 150_000_000 + (i > 2 ? -1_200_000_000 : 0) + (i > 6 ? 800_000_000 : 0);
  const inflow = 800_000_000 + Math.round(Math.random() * 600_000_000);
  const outflow = 500_000_000 + Math.round(Math.random() * 700_000_000);
  const mand = i < 5 ? 350_000_000 : i < 10 ? 180_000_000 : 50_000_000;
  const closing = opening + inflow - outflow;
  const available = closing - mand - 500_000_000;
  const alertStatus = available < 0 ? 'critical' : available < 1_000_000_000 ? 'warning' : 'safe';
  return {
    date: d.toISOString().slice(0, 10),
    label: `T${i + 1} ${d.getDate()}/${d.getMonth() + 1}`,
    openingBalance: opening,
    inflowPlanned: inflow,
    outflowPlanned: outflow,
    netCashflow: inflow - outflow,
    closingBalance: closing,
    mandatoryOutflow: mand,
    availableBalance: available,
    alertStatus,
  };
});

