const MOCK_13_WEEK = Array.from({ length: 13 }, (_, i) => {
  const opening = 11_200_000_000 + i * 320_000_000;
  const opIn = 5_500_000_000 - i * 80_000_000 + Math.round(Math.random() * 500_000_000);
  const opOut = 3_200_000_000 + i * 50_000_000 + Math.round(Math.random() * 400_000_000);
  const invOut = i === 2 ? 1_500_000_000 : i === 8 ? 2_000_000_000 : 0;
  const finIn = i === 0 ? 3_000_000_000 : 0;
  const finOut = i === 4 ? 500_000_000 : i === 10 ? 800_000_000 : 0;
  const net = opIn - opOut - invOut + finIn - finOut;
  const closing = opening + net;
  const minCash = 2_000_000_000;
  const gap = closing < minCash ? closing - minCash : 0;
  return {
    weekNumber: i + 1,
    label: `W${i + 1}`,
    openingBalance: opening,
    operatingInflow: opIn,
    operatingOutflow: opOut,
    operatingNet: opIn - opOut,
    investingOutflow: invOut,
    financingInflow: finIn,
    financingOutflow: finOut,
    netCashflow: net,
    closingBalance: closing,
    minimumCashNeeded: minCash,
    fundingGap: gap,
  };
});

